#!/bin/bash
# gh-create-issue.sh — Generated by ggen
# Create a formal work order issue using the GitHub CLI

export GH_NO_UPDATE_NOTIFIER=1

JTBD_ID=$1
PERSONA=$2
SUMMARY=$3

if [ -z "$JTBD_ID" ] || [ -z "$PERSONA" ] || [ -z "$SUMMARY" ]; then
  echo "Usage: $0 <JTBD_ID> <PERSONA> <SUMMARY>"
  exit 1
fi

echo "Creating issue in fabio-rovai/open-ontologies..."

gh issue create \
  --repo "fabio-rovai/open-ontologies" \
  --title "[$JTBD_ID] $SUMMARY" \
  --body "## Work Order Details
- **Persona**: $PERSONA
- **JTBD**: $JTBD_ID
- **Status**: Admitted
- **Law**: R ⊢ A = μ(O*)

## Summary
$SUMMARY" \
  --label "work-order"
